function useScrollReveal(threshold = 0.12) {
  const ref = useRef<HTMLDivElement>(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setVisible(true);
          observer.disconnect();
        }
      },
      { threshold }
    );
    observer.observe(el);
    return () => observer.disconnect();
  }, [threshold]);

  return { ref, visible };
}

function PortfolioTile({
  project,
  index,
  visible,
}: {
  project: Project;
  index: number;
  visible: boolean;
}) {
  const [hovered, setHovered] = useState(false);

  // Determine text color based on bg lightness (light tiles need dark text)
  const isLightBg = project.bg === "#EF9A9A" || project.bg === "#FFCDD2";

  return (
    <div
      className={`portfolio-tile relative overflow-hidden rounded-2xl cursor-pointer group ${project.colSpan} ${project.height}`}
      style={{
        backgroundColor: project.bg,
        opacity: visible ? 1 : 0,
        transform: visible ? "translateY(0) scale(1)" : "translateY(28px) scale(0.97)",
        transition: `opacity 0.6s ease ${index * 0.1}s, transform 0.6s ease ${index * 0.1}s`,
      }}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      role="article"
      aria-label={`${project.name} — ${project.category}`}
    >
      {/* Decorative background pattern — CSS geometric shapes */}
      <div className="absolute inset-0 overflow-hidden" aria-hidden="true">
        {/* Large circle */}
        <div
          className="absolute -bottom-12 -right-12 w-48 h-48 rounded-full opacity-20"
          style={{ backgroundColor: project.patternColor }}
        />
        {/* Small circle */}
        <div
          className="absolute top-6 right-10 w-16 h-16 rounded-full opacity-15"
          style={{ backgroundColor: project.patternColor }}
        />
        {/* Diagonal bar */}
        <div
          className="absolute top-0 left-1/3 w-px h-full opacity-10"
          style={{ backgroundColor: isLightBg ? "#B71C1C" : "#fff" }}
        />
        {/* Dot grid */}
        <div className="absolute top-5 left-5 grid grid-cols-3 gap-2 opacity-20">
          {Array.from({ length: 9 }).map((_, i) => (
            <div
              key={i}
              className="w-1 h-1 rounded-full"
              style={{ backgroundColor: isLightBg ? "#B71C1C" : "#fff" }}
            />
          ))}
        </div>
        {/* Corner square */}
        <div
          className="absolute bottom-8 left-6 w-10 h-10 rotate-12 opacity-15 rounded"
          style={{ backgroundColor: project.patternColor }}
        />
      </div>

      {/* Category pill — always visible */}
      <div className="absolute top-5 left-5 z-20">
        <span
          className="inline-block px-3 py-1 rounded-full text-xs font-body font-600"
          style={{
            fontFamily: "var(--font-body)",
            fontWeight: 600,
            fontSize: "0.7rem",
            letterSpacing: "0.08em",
            textTransform: "uppercase",
            backgroundColor: isLightBg ? "rgba(183,28,28,0.12)" : "rgba(255,255,255,0.18)",
            color: isLightBg ? "#B71C1C" : "#ffffff",
            backdropFilter: "blur(4px)",
          }}
        >
          {project.category}
        </span>
      </div>

      {/* Hover overlay — slides up from bottom */}
      <div
        className="portfolio-overlay absolute inset-0 z-10 flex flex-col justify-end p-7"
        style={{
          background:
            "linear-gradient(to top, rgba(127,0,0,0.92) 0%, rgba(183,28,28,0.7) 50%, transparent 100%)",
        }}
        aria-hidden={!hovered}
      >
        <p
          className="text-white font-body text-xs uppercase tracking-widest mb-2 opacity-80"
          style={{ fontFamily: "var(--font-body)", fontWeight: 500, letterSpacing: "0.14em" }}
        >
          {project.category}
        </p>
        <h3
          className="text-white font-display"
          style={{
            fontFamily: "var(--font-display)",
            fontSize: "clamp(1.2rem, 2.5vw, 1.75rem)",
            fontWeight: 800,
            lineHeight: 1.1,
            letterSpacing: "-0.02em",
          }}
        >
          {project.name}
        </h3>

        {/* View project arrow */}
        <div className="flex items-center gap-2 mt-4">
          <span
            className="text-white/80 font-body text-sm"
            style={{ fontFamily: "var(--font-body)", fontWeight: 500 }}
          >
            Ver Proyecto
          </span>
          <svg
            viewBox="0 0 16 16"
            fill="none"
            xmlns="http://www.w3.org/2000/svg"
            className="w-4 h-4 text-white"
            aria-hidden="true"
          >
            <path
              d="M3 8h10M9 4l4 4-4 4"
              stroke="white"
              strokeWidth="1.8"
              strokeLinecap="round"
              strokeLinejoin="round"
            />
          </svg>
        </div>
      </div>
    </div>
  );
}

