'use client';

import { useState, useEffect } from "react";
import Image from "next/image";
import Link from "next/link";

const navLinks = [
  { label: "Servicios", href: "#services" },
  { label: "Trabajos", href: "#portfolio" },
  { label: "Nosotros", href: "#stats" },
  { label: "Contacto", href: "#contact" },
];

export default function Navbar() {
  const [scrolled,     setScrolled]     = useState(false);
  const [menuOpen,     setMenuOpen]     = useState(false);
  const [activeLink,   setActiveLink]   = useState("");

  useEffect(() => {
    const onScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener("scroll", onScroll, { passive: true });
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  // Close mobile menu on resize to desktop
  useEffect(() => {
    const onResize = () => {
      if (window.innerWidth >= 768) setMenuOpen(false);
    };
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, []);

  const handleNavClick = (href: string) => {
    setActiveLink(href);
    setMenuOpen(false);
    const id = href.replace("#", "");
    const el = document.getElementById(id);
    if (el) {
      el.scrollIntoView({ behavior: "smooth" });
    }
  };

  return (
    <header
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-500 ${
        scrolled
          ? "bg-white/95 backdrop-blur-md shadow-sm border-b border-brand-subtle"
          : "bg-transparent"
      }`}
    >
      <div className="max-w-7xl mx-auto px-6 lg:px-8">
        <div className="flex items-center justify-between h-18 py-4">

          {/* ── Logo ──────────────────────────────────────────────── */}
          <Link
            href="/"
            className="flex items-center gap-2 group"
            aria-label="ReckTrack MD — Inicio"
          >
            <Image
              src="/logos/transparente.png"
              alt="ReckTrack Marketing Digital"
              width={160}
              height={48}
              className="h-10 w-auto object-contain"
              priority
            />
          </Link>

          {/* ── Desktop nav links ──────────────────────────────────── */}
          <nav className="hidden md:flex items-center gap-8" aria-label="Main navigation">
            {navLinks.map((link) => (
              <button
                key={link.href}
                onClick={() => handleNavClick(link.href)}
                className={`nav-link text-sm font-body font-500 tracking-wide transition-colors duration-300 ${
                  activeLink === link.href
                    ? "text-brand-primary"
                    : scrolled
                    ? "text-brand-text hover:text-brand-primary"
                    : "text-brand-text hover:text-brand-primary"
                }`}
                style={{ fontFamily: "var(--font-body)", fontWeight: 500 }}
              >
                {link.label}
              </button>
            ))}
            <button
              onClick={() => handleNavClick("#contact")}
              className="ml-2 px-5 py-2 rounded-lg bg-brand-primary text-white text-sm font-display font-600 tracking-wide hover:bg-brand-deep transition-all duration-300 hover:scale-105 active:scale-95"
              style={{ fontFamily: "var(--font-display)", fontWeight: 600 }}
            >
              Cotizar Proyecto
            </button>
          </nav>

          {/* ── Mobile hamburger ──────────────────────────────────── */}
          <button
            onClick={() => setMenuOpen((v) => !v)}
            className="md:hidden flex flex-col justify-center items-center w-10 h-10 gap-1.5 rounded-lg hover:bg-brand-subtle transition-colors duration-300"
            aria-label={menuOpen ? "Cerrar menú" : "Abrir menú"}
            aria-expanded={menuOpen}
          >
            <span
              className={`block w-5 h-0.5 bg-brand-text transition-all duration-300 ${
                menuOpen ? "rotate-45 translate-y-2" : ""
              }`}
            />
            <span
              className={`block w-5 h-0.5 bg-brand-text transition-all duration-300 ${
                menuOpen ? "opacity-0 scale-x-0" : ""
              }`}
            />
            <span
              className={`block w-5 h-0.5 bg-brand-text transition-all duration-300 ${
                menuOpen ? "-rotate-45 -translate-y-2" : ""
              }`}
            />
          </button>
        </div>
      </div>

      {/* ── Mobile dropdown ─────────────────────────────────────────── */}
      <div
        className={`md:hidden overflow-hidden transition-all duration-400 ease-in-out ${
          menuOpen ? "max-h-96 opacity-100" : "max-h-0 opacity-0"
        } bg-white/98 backdrop-blur-md border-b border-brand-subtle`}
      >
        <nav
          className="flex flex-col gap-1 px-6 py-4"
          aria-label="Navegación móvil"
        >
          {navLinks.map((link) => (
            <button
              key={link.href}
              onClick={() => handleNavClick(link.href)}
              className={`text-left px-4 py-3 rounded-lg text-base font-body font-500 transition-all duration-300 ${
                activeLink === link.href
                  ? "text-brand-primary bg-brand-subtle"
                  : "text-brand-text hover:text-brand-primary hover:bg-brand-subtle"
              }`}
              style={{ fontFamily: "var(--font-body)", fontWeight: 500 }}
            >
              {link.label}
            </button>
          ))}
          <button
            onClick={() => handleNavClick("#contact")}
            className="mt-2 px-4 py-3 rounded-lg bg-brand-primary text-white text-base font-display font-600 text-left hover:bg-brand-deep transition-all duration-300"
            style={{ fontFamily: "var(--font-display)", fontWeight: 600 }}
          >
            Cotizar →
          </button>
        </nav>
      </div>
    </header>
  );
}
