'use client';

import { useEffect, useState } from "react";

const headline = ["Construimos", "Marcas", "que", "se", "Mueven."];

export default function Hero() {
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  const handleScrollTo = (id: string) => {
    const el = document.getElementById(id);
    if (el) el.scrollIntoView({ behavior: "smooth" });
  };

  return (
    <section
      id="hero"
      className="relative h-screen flex items-center overflow-hidden"
      style={{ backgroundColor: "#F5F5F5" }}
    >
      {/* ── Decorative blobs ─────────────────────────────────────── */}
      <div
        className="absolute -top-20 -right-20 w-80 h-80 rounded-full opacity-10 pointer-events-none"
        style={{
          backgroundColor: "#B71C1C",
          animation: mounted ? "floatBlob 10s ease-in-out infinite" : "none",
        }}
        aria-hidden="true"
      />
      <div
        className="absolute -bottom-24 -left-16 w-64 h-64 rounded-full pointer-events-none"
        style={{
          backgroundColor: "#D32F2F",
          opacity: 0.07,
          animationName:           mounted ? "floatBlob" : "none",
          animationDuration:       "13s",
          animationTimingFunction: "ease-in-out",
          animationIterationCount: "infinite",
          animationDirection:      "reverse",
          animationDelay:          "2s",
          animationFillMode:       "both",
        }}
        aria-hidden="true"
      />
      <div
        className="absolute top-1/3 right-[10%] w-20 h-20 rounded-full opacity-15 border-2 pointer-events-none"
        style={{ borderColor: "#B71C1C" }}
        aria-hidden="true"
      />
      <div
        className="absolute bottom-20 right-[16%] grid grid-cols-4 gap-2.5 opacity-15 pointer-events-none"
        aria-hidden="true"
      >
        {Array.from({ length: 16 }).map((_, i) => (
          <div key={i} className="w-1 h-1 rounded-full" style={{ backgroundColor: "#B71C1C" }} />
        ))}
      </div>

      {/* ── Main content ──────────────────────────────────────────── */}
      <div className="relative z-10 max-w-7xl mx-auto px-6 lg:px-8 w-full pt-20">
        <div className="max-w-3xl">

          {/* Eyebrow */}
          <div
            className="inline-flex items-center gap-2 mb-5"
            style={{
              opacity: mounted ? 1 : 0,
              transform: mounted ? "translateY(0)" : "translateY(12px)",
              transition: "opacity 0.5s ease 0.1s, transform 0.5s ease 0.1s",
            }}
          >
            <div className="w-6 h-px" style={{ backgroundColor: "#B71C1C" }} />
            <span
              style={{
                fontFamily: "var(--font-body)",
                fontWeight: 500,
                fontSize: "0.7rem",
                color: "#B71C1C",
                letterSpacing: "0.18em",
                textTransform: "uppercase",
              }}
            >
              Agencia Digital Integral
            </span>
          </div>

          {/* ── Headline ─────────────────────────────────────────── */}
          <h1
            className="font-display mb-5"
            style={{
              fontFamily: "var(--font-display)",
              fontSize: "clamp(2.4rem, 5vw, 4.25rem)",
              fontWeight: 800,
              color: "#212121",
              lineHeight: 1.1,
              letterSpacing: "-0.025em",
            }}
          >
            {headline.map((word, i) => (
              <span
                key={i}
                className="inline-block mr-[0.22em] last:mr-0"
                style={
                  mounted
                    ? {
                        animation: "fadeUp 0.6s ease forwards",
                        animationDelay: `${0.2 + i * 0.1}s`,
                        opacity: 0,
                      }
                    : { opacity: 0 }
                }
              >
                {word === "Mueven." ? (
                  <span style={{ color: "#B71C1C" }}>{word}</span>
                ) : (
                  word
                )}
              </span>
            ))}
          </h1>

          {/* Subheadline */}
          <p
            className="font-body mb-8"
            style={{
              fontFamily: "var(--font-body)",
              fontSize: "clamp(0.95rem, 1.4vw, 1.1rem)",
              fontWeight: 400,
              color: "#757575",
              lineHeight: 1.7,
              maxWidth: "38rem",
              opacity: mounted ? 1 : 0,
              transform: mounted ? "translateY(0)" : "translateY(16px)",
              transition: "opacity 0.6s ease 0.75s, transform 0.6s ease 0.75s",
            }}
          >
            ReckTrack MD es una agencia digital orientada a resultados que combina
            marketing estratégico, desarrollo web de primer nivel y narrativa
            visual impactante para hacer crecer las marcas del mañana.
          </p>

          {/* CTAs */}
          <div
            className="flex flex-wrap gap-3 items-center mb-10"
            style={{
              opacity: mounted ? 1 : 0,
              transform: mounted ? "translateY(0)" : "translateY(16px)",
              transition: "opacity 0.6s ease 0.95s, transform 0.6s ease 0.95s",
            }}
          >
            <button
              onClick={() => handleScrollTo("contact")}
              className="btn-primary"
              style={{ fontFamily: "var(--font-display)" }}
            >
              Iniciar Proyecto
              <svg className="ml-2 w-4 h-4" viewBox="0 0 16 16" fill="none" aria-hidden="true">
                <path d="M3 8h10M9 4l4 4-4 4" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" />
              </svg>
            </button>
            <button
              onClick={() => handleScrollTo("portfolio")}
              className="btn-ghost"
              style={{ fontFamily: "var(--font-display)" }}
            >
              Ver Nuestro Trabajo
            </button>
          </div>

          {/* Trust bar */}
          <div
            className="flex flex-wrap gap-6 pt-6 border-t"
            style={{
              borderColor: "#E0E0E0",
              opacity: mounted ? 1 : 0,
              transition: "opacity 0.6s ease 1.2s",
            }}
          >
            {[
              { value: "120+", label: "Proyectos" },
              { value: "98%",  label: "Retención" },
              { value: "5★",   label: "Rating" },
              { value: "8+",   label: "Años" },
            ].map((stat) => (
              <div key={stat.label} className="flex flex-col">
                <span
                  className="font-display leading-none"
                  style={{
                    fontFamily: "var(--font-display)",
                    fontSize: "1.5rem",
                    fontWeight: 800,
                    color: "#B71C1C",
                  }}
                >
                  {stat.value}
                </span>
                <span
                  className="font-body text-xs mt-0.5 uppercase tracking-widest"
                  style={{
                    fontFamily: "var(--font-body)",
                    fontWeight: 500,
                    color: "#9E9E9E",
                    letterSpacing: "0.1em",
                    fontSize: "0.65rem",
                  }}
                >
                  {stat.label}
                </span>
              </div>
            ))}
          </div>
        </div>
      </div>


    </section>
  );
}
